import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
function homePage(){
    const page = (
        <div id = "main">
            <head>
                <title>Sign In/Sign UP</title>
            </head>
            <div id = "signin">
            <body>
            <h2>Login With Your Email Address</h2>
            <input type = "text" onChange = {this.handleChange} id = "username" placeholder = "Username"></input>
            <input type = "text" id = "password" placeholder = "Password"></input>
            <h2>Sign Up With Your Email Address</h2>
            <input type = "text" id = "emailaddress" placeholder = "Email Address"></input>
            <input type = "text" id = "pass" placeholder = "Password"></input>
                <br></br>
                <br></br>
                <input id = "submitbutton" type="submit" value="Submit" onClick= {eventHandler}/>
            </body>
            </div>
        </div>
    );
    ReactDOM.render(page, document.getElementById('root'))
    function eventHandler(){
        alert("Clicked!")
    }
}
setInterval(homePage, 1000)
